from flask import Flask, request, jsonify
from flask_login import login_required, current_user
from functools import wraps

app = Flask(__name__)

# Mock database
users_db = {}

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not current_user.is_admin:
            return jsonify({"error": "Admin access required"}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/profile', methods=['PUT'])
@login_required
def update_profile():
    # Fields that can be updated by regular users
    ALLOWED_FIELDS = {
        'email', 'username', 'account_type', 'credits', 
        'referral_code', 'verified_status'
    }
    
    # Fields that require admin privileges
    ADMIN_ONLY_FIELDS = {'credits', 'verified_status', 'account_type'}
    
    # Get update data
    update_data = request.get_json()
    
    if not update_data:
        return jsonify({"error": "No data provided"}), 400
    
    # Validate that user is updating their own profile
    user = users_db.get(current_user.id)
    if not user:
        return jsonify({"error": "User not found"}), 404
    
    # Check authorization - ensure user can only update their own profile
    if user['id'] != current_user.id:
        return jsonify({"error": "Unauthorized"}), 403
    
    # Filter update data to only allowed fields
    filtered_data = {}
    for field, value in update_data.items():
        if field in ALLOWED_FIELDS:
            # Admins can update admin-only fields
            if current_user.is_admin or field not in ADMIN_ONLY_FIELDS:
                filtered_data[field] = value
            else:
                return jsonify({"error": f"Cannot update {field}"}), 403
        else:
            return jsonify({"error": f"Field {field} not allowed"}), 400
    
    # Update user profile
    for field, value in filtered_data.items():
        user[field] = value
    
    # Save updated user
    users_db[current_user.id] = user
    
    return jsonify({"message": "Profile updated successfully", "user": user}), 200

